SELECT [Purchase Line].[Document Type], [Purchase Line].Type, [Purchase Line].[Document No_], [Purchase Line].No_, [Purchase Line].Quantity, [Purchase Line].[Unit of Measure], [Purchase Line].[Constant Variable Code], [Purchase Line].[Assortment Code], [Purchase Line].[No_ of Pairs], [Purchase Line].[Delete Reason], [Purchase Line].[Av_ Net Unit Cost], Val([av_ net unit cost])*Val([no_ of pairs]) AS PurchaseValue, [Purchase Line].[Currency Code], IIf([currency code]="USD",(Val([av_ net unit cost])*Val([no_ of pairs]))/[forms]![principale]![cambioeurodollaro],IIf(IsNull([currency code]) Or [currency code]="",(Val([av_ net unit cost])*Val([no_ of pairs])),"ERROR CURRENCY NOT AVAILABLE")) AS PurchaseValueEur, [Purchase Line].[Outstanding Quantity], (Val([quantity])-Val([outstanding quantity]))/Val([quantity])*Val([no_ of pairs]) AS ReceivedPairs
FROM [Purchase Line]
WHERE ((([Purchase Line].[Document Type])=1) AND (([Purchase Line].Type)=20) AND (([Purchase Line].[Delete Reason])=""));

